from fastapi import Depends, FastAPI, HTTPException, status
from fastapi.openapi.docs import get_swagger_ui_html, get_redoc_html
from fastapi.openapi.utils import get_openapi

app = FastAPI(docs_url=None, redoc_url=None)   # Disable auto-generated docs

async def verify_docs_access(credentials = Depends(HTTPBasic())):
    import secrets
    correct_user = secrets.compare_digest(credentials.username, "docs_user")
    correct_pass = secrets.compare_digest(credentials.password, os.environ["DOCS_PASSWORD"])
    if not (correct_user and correct_pass):
        raise HTTPException(
            status_code=401,
            headers={"WWW-Authenticate": "Basic"},
            detail="Invalid credentials"
        )

@app.get("/docs", include_in_schema=False)
async def custom_swagger(_=Depends(verify_docs_access)):
    return get_swagger_ui_html(openapi_url="/openapi.json", title="API Docs")

@app.get("/redoc", include_in_schema=False)
async def custom_redoc(_=Depends(verify_docs_access)):
    return get_redoc_html(openapi_url="/openapi.json", title="API Docs")

# /etc/nginx/sites-available/api.example.com
upstream fastapi_app {
    # Multiple Gunicorn instances for horizontal scaling
    server 127.0.0.1:8000;
    server 127.0.0.1:8001;
    keepalive 32;   # Persistent connections to upstream
}

server {
    listen 80;
    server_name api.example.com;
    return 301 https://$host$request_uri;   # Redirect to HTTPS
}

server {
    listen 443 ssl http2;
    server_name api.example.com;

    # TLS configuration
    ssl_certificate /etc/letsencrypt/live/api.example.com/fullchain.pem;
    ssl_certificate_key /etc/letsencrypt/live/api.example.com/privkey.pem;
    ssl_protocols TLSv1.2 TLSv1.3;
    ssl_ciphers ECDHE-RSA-AES256-GCM-SHA512:DHE-RSA-AES256-GCM-SHA512;
    ssl_prefer_server_ciphers off;

    # Security headers (complement FastAPI middleware)
    add_header Strict-Transport-Security "max-age=63072000; includeSubdomains" always;
    add_header X-Frame-Options DENY always;
    add_header X-Content-Type-Options nosniff always;

    # Request limits
    client_max_body_size 50M;
    client_body_timeout 60s;
    client_header_timeout 60s;

    # WebSocket support
    location /ws/ {
        proxy_pass http://fastapi_app;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_read_timeout 3600s;    # Keep WebSocket connections open
        proxy_send_timeout 3600s;
    }

    location / {
        proxy_pass http://fastapi_app;
        proxy_http_version 1.1;
        proxy_set_header Connection "";    # Enable keepalive to upstream
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;

        # Timeouts
        proxy_connect_timeout 10s;
        proxy_read_timeout 60s;
        proxy_send_timeout 60s;

        # Buffering
        proxy_buffering on;
        proxy_buffer_size 4k;
        proxy_buffers 8 4k;

        # Enable gzip (or let FastAPI's GZipMiddleware handle it)
        gzip on;
        gzip_types application/json text/plain;
        gzip_min_length 1000;
    }
}

