import json
import boto3
from functools import lru_cache

def get_secret(secret_name: str) -> dict:
    client = boto3.client("secretsmanager", region_name="us-east-1")
    response = client.get_secret_value(SecretId=secret_name)
    return json.loads(response["SecretString"])

@lru_cache()
def get_settings() -> Settings:
    if os.environ.get("ENVIRONMENT") == "production":
        secrets = get_secret("myapp/production")
        return Settings(
            database_url=secrets["DATABASE_URL"],
            secret_key=secrets["SECRET_KEY"],
            **{k: v for k, v in os.environ.items() if k in Settings.model_fields}
        )
    return Settings()   # Load from .env in development

import logging
import json
import time
from starlette.middleware.base import BaseHTTPMiddleware

class StructuredLogger(logging.Formatter):
    def format(self, record: logging.LogRecord) -> str:
        log = {
            "timestamp": self.formatTime(record, self.datefmt),
            "level": record.levelname,
            "message": record.getMessage(),
            "module": record.module,
            "function": record.funcName,
        }
        if hasattr(record, "extra"):
            log.update(record.extra)
        if record.exc_info:
            log["exception"] = self.formatException(record.exc_info)
        return json.dumps(log)

def configure_logging():
    handler = logging.StreamHandler()
    handler.setFormatter(StructuredLogger())
    logging.basicConfig(level=logging.INFO, handlers=[handler])
    logging.getLogger("uvicorn.access").setLevel(logging.WARNING)
